function toNum(x) {
  if (x === null || x === undefined) return 0;
  if (typeof x === 'number') return isFinite(x) ? x : 0;
  if (typeof x === 'string') { var n = parseFloat(x); return isFinite(n) ? n : 0; }
  return 0;
}

function compute_wq_pass_rate(raw) {
  // Optional WHO water-quality gate. The Monitoring Report schema (#8d8b1014) is FLAT and
  // has no water-quality array, so the gate only applies when a pass-rate is explicitly
  // provided via field10 (0..1 fraction or 0..100 percent) OR a nested wq array on wqSamples.
  if (raw.field10 !== undefined && raw.field10 !== null && raw.field10 !== '') {
    var pr = toNum(raw.field10);
    if (pr > 1) pr = pr / 100;
    return pr;
  }
  var arr = raw.wqSamples;
  if (arr && Array.isArray(arr) && arr.length > 0) {
    var passes = 0, total = 0;
    for (var i = 0; i < arr.length; i++) {
      var rec = arr[i] || {};
      var verdict = rec.field8 !== undefined ? rec.field8 : rec.verdict;
      if (verdict === undefined || verdict === null) continue;
      total += 1;
      if (typeof verdict === 'string' && verdict.toLowerCase().indexOf('pass') === 0) passes += 1;
    }
    return total > 0 ? (passes / total) : 1;
  }
  // No water-quality data supplied -> gate not triggered (treated as compliant).
  return 1;
}

function calc_vmr0015(doc) {
  var subj = doc.credentialSubject;
  var raw  = (subj && subj.length) ? subj[0] : doc;

  // FLAT schema mapping (matches Monitoring Report schema #8d8b1014):
  //   field3 = BE Total (tCO2e), field4 = PE Total, field5 = LE Total, field6 = ER Total
  var BE_total = toNum(raw.field3);
  var PE_total = toNum(raw.field4);
  var LE_total = toNum(raw.field5);

  var ER_total = BE_total - PE_total - LE_total;
  if (ER_total < 0) ER_total = 0;

  // WHO water-quality hard gate (VMR0015 / AMS-III.AV): only zeroes ER when an explicit
  // pass-rate is supplied and is below 95%.
  var wq_pass_rate = compute_wq_pass_rate(raw);
  if (wq_pass_rate < 0.95) ER_total = 0;

  // Uncertainty discount u_def = 0.89
  ER_total = ER_total * 0.89;

  // Write ER_y to the schema-defined mint slot (field6).
  raw.field6 = Math.round(ER_total * 100) / 100;

  return doc;
}

